import{_ as m,c as i,o as e,ae as _}from"./chunks/framework.B7Y1jjX-.js";const o=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/决策树回归.md","filePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/决策树回归.md"}'),t={name:"notes/学习/学校竞赛、项目/数学建模/课程知识/决策树回归.md"};function s(x,R,a,p,n,c){return e(),i("div",null,[...R[0]||(R[0]=[_('<h3 id="决策树回归模型公式与原理说明" tabindex="-1">决策树回归模型公式与原理说明 <a class="header-anchor" href="#决策树回归模型公式与原理说明" aria-label="Permalink to &quot;决策树回归模型公式与原理说明&quot;">​</a></h3><p>在本研究中，为了刻画孕妇 BMI 对胎儿 Y 染色体浓度最早达标孕周的影响规律，我们采用 <strong>CART（Classification and Regression Tree）回归树模型</strong>。该模型能够将复杂的非线性关系转化为一系列“如果–那么”的分裂规则，从而在解释性和预测性之间取得较好的平衡。</p><p>决策树回归的基本形式为：</p><p>f^(x)=∑m=1Mcm 1{x∈Rm},\\hat{f}(x) = \\sum_{m=1}^{M} c_m , \\mathbf{1}{x \\in R_m},f^​(x)=m=1∑M​cm​1{x∈Rm​},</p><p>其中，输入空间 Rp\\mathbb{R}^pRp 被划分为 MMM 个互不重叠的区域 {R1,R2,…,RM}{R_1, R_2, \\dots, R_M}{R1​,R2​,…,RM​}，每个区域对应树的一个叶节点；当观测值 xxx 落入区域 RmR_mRm​ 时，其预测值即为该区域的常数 cmc_mcm​。</p><p>对于每个区域 RmR_mRm​，最优常数 cmc_mcm​ 通过最小化残差平方和（SSE）得到：</p><p>cm=arg⁡min⁡c∑xi∈Rm(yi−c)2=1∣Rm∣∑xi∈Rmyi,c_m = \\arg\\min_{c} \\sum_{x_i \\in R_m} (y_i - c)^2 = \\frac{1}{|R_m|} \\sum_{x_i \\in R_m} y_i,cm​=argcmin​xi​∈Rm​∑​(yi​−c)2=∣Rm​∣1​xi​∈Rm​∑​yi​,</p><p>即区域内目标变量 yiy_iyi​（此处为最早达标孕周）的均值。</p><p>在树的生长过程中，每次切分都会选择最优的特征 jjj 与切分点 sss，使得：</p><p>RL(j,s)={x:xj&lt;s},RR(j,s)={x:xj≥s},R_{\\text{L}}(j, s) = {x : x_j &lt; s}, \\quad R_{\\text{R}}(j, s) = {x : x_j \\geq s},RL​(j,s)={x:xj​&lt;s},RR​(j,s)={x:xj​≥s},</p><p>并最小化以下目标函数：</p><p>min⁡j,s[∑xi∈RL(j,s)(yi−y‾RL)2+∑xi∈RR(j,s)(yi−y‾RR)2],\\min_{j, s} \\Bigg[ \\sum_{x_i \\in R_{\\text{L}}(j,s)} (y_i - \\overline{y}<em>{R</em>{\\text{L}}})^2 + \\sum_{x_i \\in R_{\\text{R}}(j,s)} (y_i - \\overline{y}<em>{R</em>{\\text{R}}})^2 \\Bigg],j,smin​[xi​∈RL​(j,s)∑​(yi​−y​RL​​)2+xi​∈RR​(j,s)∑​(yi​−y​RR​​)2],</p><p>其中，y‾RL\\overline{y}<em>{R</em>{\\text{L}}}y​RL​​ 与 y‾RR\\overline{y}<em>{R</em>{\\text{R}}}y​RR​​ 分别表示左右子区域内的均值。该过程通过递归分裂，不断最小化残差平方和，从而得到一棵最优的回归树。</p><p>最终，整个决策树回归模型的损失函数为：</p><p>R(T)=∑m=1M∑xi∈Rm(yi−y‾Rm)2,R(\\mathcal{T}) = \\sum_{m=1}^M \\sum_{x_i \\in R_m} (y_i - \\overline{y}_{R_m})^2,R(T)=m=1∑M​xi​∈Rm​∑​(yi​−y​Rm​​)2,</p><p>其中 T\\mathcal{T}T 表示树的结构。</p><p>在本题中，我们选取孕妇 BMI 作为自变量，最早达标孕周作为因变量，通过决策树回归对 BMI 进行监督分箱。该方法能够自动确定分割点并形成区间分组，避免了人为分组的主观性，同时保证了组间差异的显著性和组内方差的最小化。因此，该模型特别适合于探究 BMI 对 NIPT（无创产前检测）最佳检测时点的分层作用。</p>',17)])])}const y=m(t,[["render",s]]);export{o as __pageData,y as default};
